const body = $json.body || $json;
const headers = $json.headers || {};

const expectedKey = $env.LANGFLOW_API_KEY;
const providedKey = headers['x-api-key'] || headers['X-API-Key'];

// Reject keys exceeding max length to prevent truncation attacks
const MAX_KEY_LENGTH = 128;

function safeCompare(a, b) {
  // Reject keys exceeding max length first (length is not secret)
  if (a.length > MAX_KEY_LENGTH || b.length > MAX_KEY_LENGTH) {
    return false;
  }

  // Constant-time comparison: always iterate MAX_KEY_LENGTH times
  // to prevent timing attacks that could leak the expected key length
  let result = a.length ^ b.length;  // Non-zero if lengths differ

  for (let i = 0; i < MAX_KEY_LENGTH; i++) {
    // When index exceeds string length, use 0 (null byte) to avoid out-of-bounds
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  return result === 0;
}

if (expectedKey && expectedKey.length > 0) {
  if (!providedKey) {
    return [{ json: { error: 'Authentication required', code: 401 } }];
  }
  if (!safeCompare(expectedKey, providedKey)) {
    return [{ json: { error: 'Invalid API key', code: 403 } }];
  }
}

const flowId = body.flowId || $env.LANGFLOW_DEFAULT_FLOW_ID;
if (!flowId) {
  return [{ json: { error: 'flowId required', code: 400 } }];
}

// Validate flowId format (UUID v4 or alphanumeric with hyphens only)
const validIdPattern = /^[a-zA-Z0-9-]+$/;
if (!validIdPattern.test(flowId)) {
  return [{ json: { error: 'Invalid flowId format', code: 400 } }];
}

return [{
  json: {
    input_value: body.input || body.message || body.prompt || 'Hello',
    flowId: flowId,
    input_type: body.input_type || 'chat',
    output_type: body.output_type || 'chat',
    tweaks: body.tweaks || {}
  }
}];

const response = $json;

// Handle HTTP errors (when continueOnFail catches them)
if ($('Langflow API').last().error) {
  return [{
    json: {
      error: 'Upstream service error',
      code: 502
    }
  }];
}

if (response.error) {
  return [{
    json: {
      error: 'Request processing failed',
      code: response.code || 500
    }
  }];
}

// Extract outputs from Langflow response
const outputs = response.outputs || [];
const result = outputs[0]?.outputs?.[0]?.results?.message?.text ||
               outputs[0]?.outputs?.[0]?.artifacts?.message ||
               'No response';

return [{
  json: {
    text: result,
    session_id: response.session_id,
    outputs: outputs.map(o => ({
      component: o.component_id,
      type: o.type
    }))
  }
}];
